func TestEntry_Value(t *testing.T) {
	s, err := store.New(tempDir(t))
	if err != nil {
		t.Fatalf("store.New: %v", err)
	}
	defer s.Close()

	sess := s.Session()
	sess.Exec("SET k1 hello")

	entry, ok := sess.Get("k1")
	if !ok {
		t.Fatal("Get(k1) returned false")
	}
	if got := entry.Value(); got != "hello" {
		t.Errorf("Value() = %q, want hello", got)
	}
}

